DROP VIEW "public"."branch_stats";--> statement-breakpoint
CREATE VIEW "public"."branch_stats" AS (select "branch"."id", "branch"."name", count("member"."id") as "total_members", count("member"."id") filter (where "member"."status" = 'active') as "total_active_members", count("member"."id") as "total_plans", count("member"."id") filter (where "member"."status" = 'active') as "total_active_plans", count("claim"."id") as "total_claims" from "branch" left join "member" on "branch"."id" = "member"."branch_id" left join "claim" on "member"."id" = "claim"."member_id" group by "branch"."id", "branch"."name");